WITH target_station AS (SELECT id AS station_id, station_unique_id, ext_tenant_id FROM `ac_ireland_dev`.`ddm`.`dim_stations` WHERE station_model = 'AA:BB:CC:DD:EE:FF' OR station_manufacturer = 'AA:BB:CC:DD:EE:FF' OR station_type = 'AA:BB:CC:DD:EE:FF') SELECT 'state_change' AS event_type, s.id AS event_id, s.row_valid_from AS event_time, s.dim_station_id, NULL AS diagnostic_id FROM `ac_ireland_dev`.`ddm`.`dim_station_states` s JOIN target_station t ON s.dim_station_id = t.station_id WHERE s.row_valid_from >= dateadd(HOUR, -1, CURRENT_TIMESTAMP) AND s.row_valid_from IS NOT NULL UNION ALL SELECT 'diagnostic' AS event_type, NULL AS event_id, NULL AS event_time, NULL AS dim_station_id, d.id AS diagnostic_id FROM `ac_ireland_dev`.`ddm`.`dim_diagnostics` d JOIN target_station t ON d.ext_tenant_id = t.ext_tenant_id